@using System.Threading
@inject IProductService ProductService
@implements IDisposable

<div class="product-search">
    <input type="text"
           placeholder="Search products…"
           @oninput="OnSearchInput"
           value="@_query" />

    @if (_isLoading)
    {
        <div class="product-search__status">Searching…</div>
    }
    else if (_error is not null)
    {
        <div class="product-search__error">
            <span>Search failed: @_error</span>
            <button @onclick="RetrySearch">Retry</button>
        </div>
    }
    else if (_hasSearched && _results.Count == 0)
    {
        <div class="product-search__status">No products found.</div>
    }
    else if (_results.Count > 0)
    {
        <div class="product-search__results">
            @foreach (var product in _results)
            {
                <div class="product-card" @onclick="() => SelectProduct(product)">
                    <img class="product-card__image" src="@product.ImageUrl" alt="@product.Name" />
                    <div class="product-card__info">
                        <span class="product-card__name">@product.Name</span>
                        <span class="product-card__price">@product.Price.ToString("C")</span>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private string _query = string.Empty;
    private List<Product> _results = new();
    private bool _isLoading;
    private bool _hasSearched;
    private string? _error;

    private CancellationTokenSource? _debounceCts;
    private CancellationTokenSource? _searchCts;
    private bool _disposed;

    private async Task OnSearchInput(ChangeEventArgs e)
    {
        _query = e.Value?.ToString() ?? string.Empty;

        // Cancel any pending debounce timer.
        _debounceCts?.Cancel();
        _debounceCts?.Dispose();
        _debounceCts = new CancellationTokenSource();
        var debounceToken = _debounceCts.Token;

        if (string.IsNullOrWhiteSpace(_query))
        {
            CancelInflightSearch();
            _results.Clear();
            _hasSearched = false;
            _error = null;
            _isLoading = false;
            return;
        }

        try
        {
            await Task.Delay(300, debounceToken);
        }
        catch (TaskCanceledException)
        {
            // User typed again before the debounce elapsed — nothing to do.
            return;
        }

        await ExecuteSearchAsync(_query);
    }

    private async Task ExecuteSearchAsync(string query)
    {
        // Cancel any in-flight search so the service stops work it no longer needs to do.
        CancelInflightSearch();

        _searchCts = new CancellationTokenSource();
        var token = _searchCts.Token;

        _isLoading = true;
        _error = null;

        try
        {
            var results = await ProductService.SearchAsync(query, token);

            if (token.IsCancellationRequested)
                return;

            _results = results;
            _hasSearched = true;
        }
        catch (OperationCanceledException)
        {
            // Search was superseded by a newer query — silently discard.
        }
        catch (Exception ex)
        {
            if (!token.IsCancellationRequested)
            {
                _error = ex.Message;
                _results.Clear();
            }
        }
        finally
        {
            if (!token.IsCancellationRequested)
            {
                _isLoading = false;
            }
        }
    }

    private async Task RetrySearch()
    {
        if (!string.IsNullOrWhiteSpace(_query))
        {
            await ExecuteSearchAsync(_query);
        }
    }

    private async Task SelectProduct(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private void CancelInflightSearch()
    {
        _searchCts?.Cancel();
        _searchCts?.Dispose();
        _searchCts = null;
    }

    public void Dispose()
    {
        if (_disposed) return;
        _disposed = true;

        _debounceCts?.Cancel();
        _debounceCts?.Dispose();
        CancelInflightSearch();
    }
}

